import { verify } from 'vex-sdk';

import { InvoiceSchema } from './schemas';

const extractInvoice = async (query: string) => {
  const response = await queryEngine.query({
    query,
    outputSchema: InvoiceSchema
  });

  const result = await verify({
    checks: [
      'schemaCompliance',
      { fieldAccuracy: { fields: ['invoiceNumber', 'totalAmount'], threshold: 0.9 } },
      'typeConsistency',
      'completeness'
    ],
    riskProfile: 'medium',
    payload: response
  });

  return result.verified ? result.value : null;
};
